    <main id="top" class="book-page">
      <section class="book-hero section" aria-labelledby="book-title" data-reveal>
        <div class="book-copy">
          <span class="section-kicker">Book a Demo</span>
          <h1 id="book-title">See how YeneSchool fits your school.</h1>
          <p>Request a walkthrough for admissions, attendance, exams, report cards, parent access, finance, and the setup path your team needs.</p>
          <div class="book-points" aria-label="Demo topics">
            <span>Module walkthrough</span>
            <span>Pricing guidance</span>
            <span>Rollout planning</span>
          </div>
        </div>
        <div class="contact-form-shell book-form-shell">
          <form class="contact-form" data-contact-form>
            <div class="form-row">
              <label><span>Name</span><input type="text" name="name" autocomplete="name" required /></label>
              <label><span>School name</span><input type="text" name="school" autocomplete="organization" required /></label>
            </div>
            <div class="form-row">
              <label><span>Email</span><input type="email" name="email" autocomplete="email" required /></label>
              <label><span>Phone</span><input type="tel" name="phone" autocomplete="tel" /></label>
            </div>
            <label><span>Demo focus</span><select name="message_focus" required><option value="">Choose one</option><option value="Full school walkthrough">Full school walkthrough</option><option value="Admissions and academics">Admissions and academics</option><option value="Report cards and exams">Report cards and exams</option><option value="Parent portal and communication">Parent portal and communication</option><option value="Pricing and implementation">Pricing and implementation</option></select></label>
            <input type="hidden" name="topic" value="Book a demo" />
            <label><span>What should we prepare?</span><textarea name="message" rows="6" required placeholder="Tell us your school size, grades, active modules, and the best time to contact you."></textarea></label>
            <button class="primary-btn gradient-btn contact-submit" type="submit"><span data-contact-submit-label>Request demo</span></button>
            <p class="contact-form-status" data-contact-status role="status" aria-live="polite"></p>
          </form>
        </div>
      </section>

      <section class="section booking-steps" aria-labelledby="booking-steps-title" data-reveal>
        <div class="section-heading compact">
          <p class="eyebrow">What Happens Next</p>
          <h2 id="booking-steps-title">A focused demo, not a generic sales call.</h2>
        </div>
        <div class="booking-step-grid">
          <article><strong>1</strong><h3>Share your school context</h3><p>Tell us your grade range, current process, and the areas you want to improve first.</p></article>
          <article><strong>2</strong><h3>Walk through matching modules</h3><p>We focus on the dashboards and workflows that match your owner, registrar, teacher, finance, and parent needs.</p></article>
          <article><strong>3</strong><h3>Plan setup and pricing</h3><p>You get the clearest next step for rollout, training, migration, and the plan that fits your school size.</p></article>
        </div>
      </section>
    </main>

